import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { Star, TrendingUp, Zap, Heart, Code, Gamepad2, Filter, Info, ArrowRight, Search, Sparkles, User, Lightbulb } from 'lucide-react';
import { LayoutWithStats } from '../types';

type PreferenceType = 'comfort' | 'speed' | 'gaming' | 'programming' | 'pinky_strain';

interface Preference {
  id: PreferenceType;
  name: string;
  description: string;
  icon: React.ReactNode;
  color: string;
}

interface RecommendationError {
  message: string;
  details?: string;
}

interface OccupationMapping {
  keywords: string[];
  priority: PreferenceType;
  confidence: number;
}

// Occupation to preference mapping algorithm
const occupationMappings: OccupationMapping[] = [
  // Programming & Tech
  { keywords: [
    'developer', 'programmer', 'engineer', 'software', 'coder', 'tech', 'web', 'app', 'frontend', 'backend', 'fullstack', 'devops', 'sysadmin', 'architect', 'analyst',
    'coding', 'programming', 'development', 'javascript', 'python', 'java', 'react', 'node', 'angular', 'vue', 'typescript', 'php', 'ruby', 'go', 'rust', 'c++', 'c#',
    'database', 'sql', 'api', 'cloud', 'aws', 'azure', 'docker', 'kubernetes', 'git', 'github', 'linux', 'unix', 'bash', 'terminal', 'cli', 'ide', 'vscode', 'vim',
    'machine learning', 'ai', 'data science', 'ml', 'artificial intelligence', 'algorithms', 'data structures', 'computer science', 'cs', 'it', 'information technology',
    'cybersecurity', 'security', 'network', 'system admin', 'database admin', 'qa', 'quality assurance', 'testing', 'automation', 'ci/cd', 'agile', 'scrum'
  ], priority: 'programming', confidence: 0.95 },
  
  // Gaming
  { keywords: [
    'gamer', 'esports', 'streamer', 'gaming', 'twitch', 'youtube gaming', 'competitive', 'fps', 'moba', 'mmo', 'rpg', 'rts', 'battle royale',
    // Popular games
    'fortnite', 'valorant', 'csgo', 'counter-strike', 'cs2', 'league of legends', 'lol', 'dota', 'dota2', 'apex legends', 'cod', 'call of duty', 'warzone',
    'overwatch', 'rocket league', 'minecraft', 'wow', 'world of warcraft', 'pubg', 'rainbow six', 'r6', 'siege', 'battlefield', 'destiny', 'halo',
    'starcraft', 'hearthstone', 'diablo', 'path of exile', 'poe', 'elder scrolls', 'skyrim', 'fallout', 'gta', 'grand theft auto', 'red dead',
    'witcher', 'cyberpunk', 'assassins creed', 'fifa', 'nba 2k', 'madden', 'tekken', 'street fighter', 'mortal kombat', 'smash bros',
    // Gaming platforms and terms
    'steam', 'epic games', 'origin', 'battle.net', 'xbox', 'playstation', 'nintendo', 'pc gaming', 'console', 'controller', 'mouse', 'keyboard',
    'streaming', 'obs', 'discord', 'teamspeak', 'ventrilo', 'clan', 'guild', 'tournament', 'ladder', 'ranked', 'casual', 'hardcore',
    'speedrun', 'speedrunning', 'tas', 'tool assisted', 'world record', 'wr', 'personal best', 'pb', 'grinding', 'farming', 'meta'
  ], priority: 'gaming', confidence: 0.9 },
  
  // Speed-focused roles
  { keywords: [
    'data entry', 'transcription', 'secretary', 'assistant', 'clerk', 'typist', 'journalist', 'reporter', 'court reporter', 'translator', 'copywriter',
    'administrative', 'admin', 'receptionist', 'customer service', 'call center', 'support', 'helpdesk', 'virtual assistant', 'va',
    'stenographer', 'scribe', 'note taker', 'minutes', 'documentation', 'fast typing', 'speed typing', 'typing speed', 'wpm', 'words per minute',
    'transcriptionist', 'captioning', 'subtitles', 'live captioning', 'real time', 'court stenographer', 'medical transcription',
    'social media manager', 'content moderator', 'chat moderator', 'live chat', 'customer support', 'technical support', 'help desk'
  ], priority: 'speed', confidence: 0.85 },
  
  // Comfort-focused (long hours)
  { keywords: [
    'writer', 'author', 'editor', 'blogger', 'content creator', 'researcher', 'accountant', 'bookkeeper', 'lawyer', 'paralegal', 'student', 'academic', 'professor',
    'novelist', 'freelance writer', 'technical writer', 'copywriter', 'ghostwriter', 'screenwriter', 'playwright', 'poet', 'journalism',
    'proofreader', 'copy editor', 'line editor', 'developmental editor', 'manuscript', 'publishing', 'self-publishing', 'kindle', 'ebook',
    'research', 'thesis', 'dissertation', 'phd', 'masters', 'doctorate', 'graduate student', 'undergraduate', 'college', 'university',
    'librarian', 'archivist', 'curator', 'historian', 'archaeologist', 'anthropologist', 'sociologist', 'psychologist', 'therapist',
    'legal', 'attorney', 'barrister', 'solicitor', 'law firm', 'legal assistant', 'legal secretary', 'paralegal', 'law student', 'law school',
    'accounting', 'bookkeeping', 'cpa', 'certified public accountant', 'tax preparation', 'auditor', 'financial analyst', 'finance',
    'long hours', 'extended typing', 'marathon typing', 'all day typing', 'work from home', 'remote work', 'telecommuting',
    'novelist', 'fiction writer', 'non-fiction', 'biography', 'memoir', 'travel writer', 'food blogger', 'lifestyle blogger'
  ], priority: 'comfort', confidence: 0.8 },
  
  // Pinky strain relief
  { keywords: [
    'arthritis', 'rsi', 'carpal tunnel', 'injury', 'strain', 'elderly', 'senior', 'disability', 'ergonomic', 'health', 'medical condition',
    'repetitive strain injury', 'tendonitis', 'tendinitis', 'chronic pain', 'joint pain', 'finger pain', 'hand pain', 'wrist pain',
    'fibromyalgia', 'chronic fatigue', 'lupus', 'multiple sclerosis', 'ms', 'parkinsons', 'tremor', 'limited mobility', 'motor impairment',
    'occupational therapy', 'physical therapy', 'pt', 'ot', 'rehabilitation', 'recovery', 'adaptive', 'accessible', 'accessibility',
    'ergonomics', 'workplace injury', 'work-related injury', 'overuse', 'strain injury', 'typing injury', 'computer injury',
    'senior citizen', 'elderly person', 'retirement', 'retired', 'golden years', 'older adult', 'mature adult',
    'weak fingers', 'weak hands', 'limited dexterity', 'reduced mobility', 'stiff joints', 'joint stiffness', 'inflammation',
    'pinky weakness', 'pinky problems', 'finger weakness', 'hand weakness', 'grip strength', 'fine motor skills'
  ], priority: 'pinky_strain', confidence: 0.95 },
  
  // General productivity and efficiency
  { keywords: [
    'productivity', 'efficiency', 'fast typing', 'speed', 'quick typing', 'rapid typing', 'typing practice', 'touch typing',
    'business', 'corporate', 'office work', 'professional', 'executive', 'manager', 'supervisor', 'team lead',
    'entrepreneur', 'startup', 'freelancer', 'consultant', 'contractor', 'self-employed', 'small business',
    'email', 'communication', 'correspondence', 'meetings', 'presentations', 'reports', 'documentation'
  ], priority: 'speed', confidence: 0.7 },
  
  // General comfort and wellness
  { keywords: [
    'comfort', 'ergonomic', 'health', 'wellness', 'wellbeing', 'healthy typing', 'comfortable typing', 'relaxed typing',
    'posture', 'good posture', 'back pain', 'neck pain', 'shoulder pain', 'workplace wellness', 'office ergonomics',
    'prevention', 'injury prevention', 'health conscious', 'wellness focused', 'self care', 'mindful typing'
  ], priority: 'comfort', confidence: 0.7 },
  
  // Additional programming related
  { keywords: [
    'open source', 'github', 'stackoverflow', 'stack overflow', 'hackathon', 'bootcamp', 'coding bootcamp',
    'software development', 'web development', 'mobile development', 'game development', 'app development'
  ], priority: 'programming', confidence: 0.8 }
];

const RecommendationsPage: React.FC = () => {
  const [selectedPreference, setSelectedPreference] = useState<PreferenceType>('comfort');
  const [recommendations, setRecommendations] = useState<LayoutWithStats[]>([]);
  const [loading, setLoading] = useState(false);
  const [allLayouts, setAllLayouts] = useState<LayoutWithStats[]>([]);
  const [error, setError] = useState<RecommendationError | null>(null);
  const [occupationQuery, setOccupationQuery] = useState('');
  const [suggestedPreference, setSuggestedPreference] = useState<{preference: PreferenceType, confidence: number} | null>(null);

  const preferences: Preference[] = [
    {
      id: 'comfort',
      name: 'Comfort',
      description: 'Minimize finger strain and maximize typing comfort',
      icon: <Heart className="w-6 h-6" />,
      color: 'from-pink-500 to-rose-500'
    },
    {
      id: 'speed',
      name: 'Speed',
      description: 'Optimize for maximum typing speed and flow',
      icon: <Zap className="w-6 h-6" />,
      color: 'from-yellow-500 to-orange-500'
    },
    {
      id: 'gaming',
      name: 'Gaming',
      description: 'Best layouts for gaming performance',
      icon: <Gamepad2 className="w-6 h-6" />,
      color: 'from-blue-500 to-indigo-500'
    },
    {
      id: 'programming',
      name: 'Programming',
      description: 'Optimized for coding and special characters',
      icon: <Code className="w-6 h-6" />,
      color: 'from-green-500 to-emerald-500'
    },
    {
      id: 'pinky_strain',
      name: 'Pinky Relief',
      description: 'Minimize pinky finger usage and strain',
      icon: <TrendingUp className="w-6 h-6" />,
      color: 'from-purple-500 to-violet-500'
    }
  ];

  useEffect(() => {
    fetchAllLayouts();
  }, []);

  useEffect(() => {
    if (allLayouts.length > 0) {
      generateRecommendations();
    }
  }, [selectedPreference, allLayouts]);

  const fetchAllLayouts = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch('/api/layouts');
      if (response.ok) {
        const data = await response.json();
        setAllLayouts(data);
      } else {
        const errorMessage = response.status === 404 
          ? 'Layout data not found. Please ensure the backend is running.'
          : `Failed to fetch layouts (${response.status})`;
        setError({ 
          message: errorMessage,
          details: 'Unable to load keyboard layout data from the server.'
        });
      }
    } catch (error) {
      console.error('Error fetching layouts:', error);
      setError({ 
        message: 'Unable to connect to the server',
        details: 'Please check your internet connection and try again.'
      });
    } finally {
      setLoading(false);
    }
  };

  const generateRecommendations = async () => {
    if (allLayouts.length === 0) return;
    
    setLoading(true);
    setError(null);
    
    try {
      // Try to get recommendations from API first
      const response = await fetch('/api/recommendations', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ preferences: selectedPreference }),
      });
      
      if (response.ok) {
        const data = await response.json();
        setRecommendations(data);
        setLoading(false);
        return;
      }
    } catch (error) {
      console.log('API recommendations not available, using client-side scoring:', error);
    }
    
    // Fallback to client-side scoring if API is not available
    try {
      const scored = scoreLayouts(allLayouts, selectedPreference);
      setRecommendations(scored.slice(0, 8)); // Show top 8 recommendations
    } catch (error) {
      console.error('Error generating recommendations:', error);
      setError({ 
        message: 'Failed to generate recommendations',
        details: 'Unable to analyze layout data. Please try again.'
      });
    } finally {
      setLoading(false);
    }
  };

  const scoreLayouts = (layouts: LayoutWithStats[], preference: PreferenceType): LayoutWithStats[] => {
    const weights = {
      comfort: {
        effort: -0.25,
        distance: -0.2,
        pinky_distance: -0.15,
        pinky_off_home_pct: -0.1,
        same_finger_bigrams_pct: -0.15,
        lateral_stretch_pct: -0.15
      },
      speed: {
        roll_in_pct: 0.3,
        roll_out_pct: 0.2,
        trigram_alt_pct: 0.25,
        same_finger_bigrams_pct: -0.25
      },
      gaming: {
        effort: -0.2,
        distance: -0.15,
        col5_6_pct: -0.2,
        roll_in_pct: 0.2,
        two_row_jumps_pct: -0.15,
        pinky_scissors_pct: -0.1
      },
      programming: {
        lateral_stretch_pct: -0.2,
        skip_bigrams_pct: -0.15,
        effort: -0.2,
        same_finger_bigrams_pct: -0.15,
        trigram_alt_pct: 0.15,
        roll_in_pct: 0.15
      },
      pinky_strain: {
        pinky_distance: -0.3,
        pinky_off_home_pct: -0.25,
        pinky_scissors_pct: -0.2,
        col5_6_pct: -0.25
      }
    };

    const selectedWeights = weights[preference];

    return layouts.map(layout => {
      let score = 0;
      
      for (const [metric, weight] of Object.entries(selectedWeights)) {
        const value = (layout as any)[metric];
        if (value !== null && value !== undefined) {
          let normalizedValue = value;
          if (metric.endsWith('_pct')) {
            normalizedValue = value / 100;
          }
          score += normalizedValue * weight;
        }
      }
      
      return {
        ...layout,
        recommendation_score: score
      };
    }).sort((a, b) => (b.recommendation_score || 0) - (a.recommendation_score || 0));
  };

  const getMetricColor = (value: number | undefined, good: number, bad: number, lowerIsBetter: boolean = true) => {
    if (value === undefined) return 'text-gray-400';
    if (lowerIsBetter) {
      return value <= good ? 'text-green-500' : value >= bad ? 'text-red-500' : 'text-yellow-500';
    } else {
      return value >= good ? 'text-green-500' : value <= bad ? 'text-red-500' : 'text-yellow-500';
    }
  };

  // Occupation priority detection algorithm
  const analyzeOccupation = useCallback((query: string) => {
    if (!query.trim()) {
      setSuggestedPreference(null);
      return;
    }

    const lowercaseQuery = query.toLowerCase();
    let bestMatch: {preference: PreferenceType, confidence: number} | null = null;

    // Score each mapping based on keyword matches
    for (const mapping of occupationMappings) {
      let totalScore = 0;
      let matchCount = 0;

      for (const keyword of mapping.keywords) {
        if (lowercaseQuery.includes(keyword.toLowerCase())) {
          // Boost score for exact word matches vs partial matches
          const isExactWord = new RegExp(`\\b${keyword.toLowerCase()}\\b`).test(lowercaseQuery);
          const score = isExactWord ? 1.0 : 0.5;
          totalScore += score;
          matchCount++;
        }
      }

      if (matchCount > 0) {
        // Calculate confidence: base confidence * match strength * keyword coverage
        const matchStrength = totalScore / mapping.keywords.length;
        const finalConfidence = mapping.confidence * Math.min(matchStrength * 2, 1.0);
        
        if (!bestMatch || finalConfidence > bestMatch.confidence) {
          bestMatch = {
            preference: mapping.priority,
            confidence: finalConfidence
          };
        }
      }
    }

    setSuggestedPreference(bestMatch);
  }, []);

  // Handle occupation search input
  const handleOccupationSearch = (query: string) => {
    setOccupationQuery(query);
    analyzeOccupation(query);
  };

  // Apply suggested preference
  const applySuggestion = () => {
    if (suggestedPreference) {
      setSelectedPreference(suggestedPreference.preference);
      setSuggestedPreference(null); // Clear suggestion after applying
    }
  };


  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 py-8">
      <div className="max-w-7xl mx-auto px-4">
        {/* Header */}
        <div className="text-center mb-8">
          <div className="flex items-center justify-center gap-3 mb-6">
            <Lightbulb className="w-12 h-12 text-purple-400" />
          <h1 className="text-5xl font-bold bg-gradient-to-r from-purple-400 via-pink-400 to-blue-400 bg-clip-text text-transparent leading-normal pb-1">
            layout recommendations
          </h1>
          </div>
          <p className="text-xl text-gray-600 dark:text-gray-300 max-w-5xl mx-auto leading-relaxed">
            Get personalized keyboard layout recommendations based on your typing preferences and use case.
          </p>
        </div>

        {/* Occupation Priority Search */}
        <div className="bg-white dark:bg-gray-800 rounded-xl p-6 mb-8 shadow-lg">
          <div className="flex items-center gap-2 mb-4">
            <Search className="text-purple-600" size={24} />
            <h2 className="text-xl font-semibold">Priority Detection</h2>
          </div>
          <p className="text-gray-600 dark:text-gray-300 text-sm mb-4">
            Tell us about your occupation or interests, and we'll detect the best priority for you!
          </p>
          
          <div className="relative">
            <User className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
            <input
              type="text"
              placeholder="e.g., software developer, gamer, writer, data entry clerk, student..."
              value={occupationQuery}
              onChange={(e) => handleOccupationSearch(e.target.value)}
              className="w-full pl-10 pr-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg shadow-sm placeholder-gray-400 dark:placeholder-gray-400 bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-purple-500 transition-all"
            />
          </div>
          
          {/* Priority Suggestion Display */}
          {suggestedPreference && (
            <div className="mt-4 p-4 bg-gradient-to-r from-purple-50 to-blue-50 dark:from-purple-900/20 dark:to-blue-900/20 rounded-lg border border-purple-200 dark:border-purple-800">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="flex-shrink-0">
                    <div className={`w-10 h-10 rounded-lg bg-gradient-to-r ${preferences.find(p => p.id === suggestedPreference.preference)?.color} flex items-center justify-center text-white`}>
                      {preferences.find(p => p.id === suggestedPreference.preference)?.icon}
                    </div>
                  </div>
                  <div>
                    <div className="flex items-center gap-2">
                      <span className="text-sm font-semibold text-purple-700 dark:text-purple-300">
                        🎯 Detected Priority:
                      </span>
                      <span className="font-bold text-gray-900 dark:text-white">
                        {preferences.find(p => p.id === suggestedPreference.preference)?.name}
                      </span>
                    </div>
                    <p className="text-xs text-gray-600 dark:text-gray-400 mt-1">
                      {preferences.find(p => p.id === suggestedPreference.preference)?.description}
                    </p>
                  </div>
                </div>
                <button
                  onClick={applySuggestion}
                  className="px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors text-sm font-medium flex items-center gap-2"
                >
                  <ArrowRight size={16} />
                  Apply
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Preference Selection */}
        <div className="bg-white dark:bg-gray-800 rounded-xl p-6 mb-8 shadow-lg">
          <div className="flex items-center gap-2 mb-4">
            <Filter className="text-purple-600" size={24} />
            <h2 className="text-xl font-semibold">Choose Your Priority</h2>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
            {preferences.map((pref) => (
              <button
                key={pref.id}
                onClick={() => setSelectedPreference(pref.id)}
                className={`p-4 rounded-lg border-2 transition-all ${
                  selectedPreference === pref.id
                    ? 'border-purple-500 bg-purple-50 dark:bg-purple-900/20'
                    : 'border-gray-200 dark:border-gray-700 hover:border-purple-300'
                }`}
              >
                <div className={`w-12 h-12 rounded-lg bg-gradient-to-r ${pref.color} flex items-center justify-center text-white mb-3 mx-auto`}>
                  {pref.icon}
                </div>
                <h3 className="font-semibold mb-1">{pref.name}</h3>
                <p className="text-xs text-gray-600 dark:text-gray-400">{pref.description}</p>
              </button>
            ))}
          </div>
        </div>

        {/* Error Display */}
        {error && (
          <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl p-6 mb-8">
            <div className="flex items-center gap-2 mb-2">
              <div className="text-red-600 dark:text-red-400 font-semibold">{error.message}</div>
            </div>
            {error.details && (
              <p className="text-red-600 dark:text-red-400 text-sm">{error.details}</p>
            )}
            <button
              onClick={() => {
                setError(null);
                fetchAllLayouts();
              }}
              className="mt-3 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors text-sm"
            >
              Try Again
            </button>
          </div>
        )}

        {/* Recommendations */}
        {loading ? (
          <div className="flex flex-col items-center justify-center py-12">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600 mb-4"></div>
            <p className="text-gray-600 dark:text-gray-300">
              {allLayouts.length === 0 ? 'Loading keyboard layouts...' : 'Generating recommendations...'}
            </p>
          </div>
        ) : error ? null : (
          <div>
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <Star className="text-yellow-500" size={24} />
                <h2 className="text-2xl font-bold">Recommended for {preferences.find(p => p.id === selectedPreference)?.name}</h2>
              </div>
              {allLayouts.length > 0 && (
                <Link
                  to="/layouts"
                  className="flex items-center gap-2 px-4 py-2 bg-gray-100 dark:bg-gray-800 hover:bg-gray-200 dark:hover:bg-gray-700 rounded-lg transition-colors text-sm font-medium"
                >
                  <Search size={16} />
                  Browse All Layouts
                  <ArrowRight size={16} />
                </Link>
              )}
            </div>
            
            {recommendations.length > 0 ? (
              <>
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                  {recommendations.map((layout, index) => (
                    <Link
                      key={layout.id}
                      to={`/layouts/${encodeURIComponent(layout.slug)}`}
                      className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg hover:shadow-xl transition-all hover:scale-[1.02] border-2 hover:border-purple-300 dark:hover:border-purple-700"
                    >
                      <div className="flex items-start justify-between mb-4">
                        <div>
                          <div className="flex items-center gap-2 mb-2">
                            <span className="bg-purple-100 dark:bg-purple-900 text-purple-600 dark:text-purple-400 text-sm font-bold px-2 py-1 rounded">
                              #{index + 1}
                            </span>
                            <h3 className="text-xl font-bold">{layout.name}</h3>
                          </div>
                          <p className="text-gray-600 dark:text-gray-400 text-sm">{layout.description}</p>
                          <span className="inline-block bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 text-xs px-2 py-1 rounded mt-2">
                            {layout.type}
                          </span>
                        </div>
                        {layout.recommendation_score && (
                          <div className="text-right">
                            <div className="text-2xl font-bold text-purple-600">
                              {Math.round((layout.recommendation_score + 1) * 50)}
                            </div>
                            <div className="text-xs text-gray-500">Match Score</div>
                          </div>
                        )}
                      </div>

                      {/* Key Metrics */}
                      <div className="grid grid-cols-4 gap-4 text-sm">
                        <div className="text-center">
                          <div className="text-xs text-gray-500 mb-1">Effort</div>
                          <div className={`font-semibold ${getMetricColor(layout.effort, 1.2, 1.4)}`}>
                            {layout.effort?.toFixed(2) || 'N/A'}
                          </div>
                        </div>
                        <div className="text-center">
                          <div className="text-xs text-gray-500 mb-1">SFBs</div>
                          <div className={`font-semibold ${getMetricColor(layout.same_finger_bigrams_pct, 2, 5)}`}>
                            {layout.same_finger_bigrams_pct?.toFixed(1)}%
                          </div>
                        </div>
                        <div className="text-center">
                          <div className="text-xs text-gray-500 mb-1">Roll In</div>
                          <div className={`font-semibold ${getMetricColor(layout.roll_in_pct, 15, 8, false)}`}>
                            {layout.roll_in_pct?.toFixed(1)}%
                          </div>
                        </div>
                        <div className="text-center">
                          <div className="text-xs text-gray-500 mb-1">Alt</div>
                          <div className={`font-semibold ${getMetricColor(layout.trigram_alt_pct, 25, 15, false)}`}>
                            {layout.trigram_alt_pct?.toFixed(1)}%
                          </div>
                        </div>
                      </div>

                      {/* Why Recommended */}
                      <div className="mt-4 p-3 bg-purple-50 dark:bg-purple-900/20 rounded-lg">
                        <div className="flex items-center gap-1 mb-1">
                          <Info size={14} className="text-purple-600" />
                          <span className="text-xs font-semibold text-purple-600">Why recommended:</span>
                        </div>
                        <p className="text-xs text-gray-600 dark:text-gray-400">
                          {getRecommendationReason(layout, selectedPreference)}
                        </p>
                      </div>
                    </Link>
                  ))}
                </div>
                
                {/* Browse All Layouts Section */}
                <div className="mt-12 bg-gradient-to-r from-purple-50 to-blue-50 dark:from-purple-900/20 dark:to-blue-900/20 rounded-xl p-6 text-center">
                  <h3 className="text-lg font-semibold mb-2">Want to explore more?</h3>
                  <p className="text-gray-600 dark:text-gray-300 mb-4">
                    Browse our complete collection of {allLayouts.length} keyboard layouts with detailed analysis and comparisons.
                  </p>
                  <Link
                    to="/layouts"
                    className="inline-flex items-center gap-2 px-6 py-3 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors font-medium"
                  >
                    <Search size={20} />
                    Browse All Layouts
                    <ArrowRight size={20} />
                  </Link>
                </div>
              </>
            ) : (
              <div className="text-center py-12">
                <div className="max-w-md mx-auto">
                  <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
                    No recommendations available
                  </h3>
                  <p className="text-gray-500 dark:text-gray-400 mb-6">
                    {allLayouts.length === 0 
                      ? 'No layout data available. Please check your server connection.'
                      : 'Unable to generate recommendations with the current data. Try exploring all layouts instead.'
                    }
                  </p>
                  {allLayouts.length > 0 && (
                    <Link
                      to="/layouts"
                      className="inline-flex items-center gap-2 px-6 py-3 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors font-medium"
                    >
                      <Search size={20} />
                      Browse All Layouts
                      <ArrowRight size={20} />
                    </Link>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );

  function getRecommendationReason(layout: LayoutWithStats, preference: PreferenceType): string {
    switch (preference) {
      case 'comfort':
        return `Low effort (${layout.effort?.toFixed(2)}) and minimal same-finger bigrams (${layout.same_finger_bigrams_pct?.toFixed(1)}%) for comfortable typing.`;
      case 'speed':
        return `High roll percentage (${((layout.roll_in_pct || 0) + (layout.roll_out_pct || 0)).toFixed(1)}%) and strong alternation (${layout.trigram_alt_pct?.toFixed(1)}%) for fast typing.`;
      case 'gaming':
        return `Optimized key placement for gaming with low effort (${layout.effort?.toFixed(2)}) and good accessibility.`;
      case 'programming':
        return `Low lateral stretches (${layout.lateral_stretch_pct?.toFixed(1)}%) and balanced metrics for coding comfort.`;
      case 'pinky_strain':
        return `Minimized pinky usage (${layout.pinky_off_home_pct?.toFixed(1)}% off-home) and reduced pinky strain.`;
      default:
        return 'Well-balanced layout suitable for general use.';
    }
  }
};

export default RecommendationsPage;
